157	/**
158	 * Resolve a template engine's givens map using a variables context.
159	 * '$writ' → WritDoc, '$vars.<key>' → spiderConfig.variables[key].
160	 * Keys resolving to undefined are omitted from the output.
161	 * Non-'$' prefixed values are passed through as literals.
162	 */
163	function resolveGivens(
164	  givens: Record<string, unknown> | undefined,
165	  context: { writ: WritDoc; spiderConfig: SpiderConfig },
166	): Record<string, unknown> {
167	  const result: Record<string, unknown> = {};
168	  for (const [key, value] of Object.entries(givens ?? {})) {
169	    if (typeof value !== 'string' || !value.startsWith('$')) {
170	      result[key] = value;
171	    } else {
172	      const normalized = normalizeVarRef(value);
173	      if (normalized === '$writ') {
174	        result[key] = context.writ;
175	      } else if (/^\$vars\.[a-zA-Z_][a-zA-Z0-9_]*$/.test(normalized)) {
176	        const varKey = normalized.slice('$vars.'.length);
177	        const resolved = (context.spiderConfig.variables ?? {})[varKey];
178	        if (resolved !== undefined) {
179	          result[key] = resolved;
180	        }
181	        // undefined → omit key entirely
182	      }
183	      // Unrecognized $-prefixed strings are caught at validation time
184	    }
185	  }
186	  return result;
187	}
