194	  context: { writ: WritDoc; spiderConfig: SpiderConfig },
195	): { engines: EngineInstance[]; resolutionEngineId?: string } {
196	  const engines: EngineInstance[] = template.engines.map((entry) => ({
197	    id: entry.id,
198	    designId: entry.designId,
199	    status: 'pending' as const,
200	    upstream: entry.upstream ?? [],
201	    givensSpec: resolveGivens(entry.givens, context),
