/**
 * Crawl tool tests — unit tests for the crawl-one and crawl-continual tools.
 *
 * Tests handler logic directly (no full Spider apparatus needed), with a
 * minimal guild mock that provides a controllable SpiderApi stub.
 *
 * Uses the native Node test runner consistent with the rest of the package.
 */

import { describe, it, beforeEach, afterEach } from 'node:test';
import assert from 'node:assert/strict';

import { setGuild, clearGuild } from '@shardworks/nexus-core';
import type { Guild, GuildConfig, LoadedKit, LoadedApparatus } from '@shardworks/nexus-core';
import type { SpiderApi, SpiderConfig, CrawlResult } from '../types.ts';

import crawlOneTool from './crawl-one.ts';
import crawlContinualTool from './crawl-continual.ts';

// ── Helpers ────────────────────────────────────────────────────────────

/** Returns a minimal guild with a controllable SpiderApi mock. */
function makeGuild(
  crawlFn: () => Promise<CrawlResult | null>,
  spiderConfig: Partial<SpiderConfig> = {},
): Guild {
  const mockSpider: SpiderApi = {
    crawl: crawlFn,
    show: async () => { throw new Error('not implemented'); },
    list: async () => [],
    forWrit: async () => null,
    resume: async () => {},
    getBlockType: () => undefined,
  };

  const fakeGuildConfig: GuildConfig = {
    name: 'test-guild',
    nexus: '0.0.0',
    plugins: [],
    spider: spiderConfig as SpiderConfig,
  };

  const fakeGuild: Guild = {
    home: '/tmp/test-guild',
    apparatus<T>(name: string): T {
      if (name === 'spider') return mockSpider as unknown as T;
      throw new Error(`Apparatus "${name}" not found`);
    },
    config<T>(_pluginId: string): T { return {} as T; },
    writeConfig() {},
    guildConfig() { return fakeGuildConfig; },
    kits(): LoadedKit[] { return []; },
    apparatuses(): LoadedApparatus[] { return []; },
  };

  return fakeGuild;
}

/** Returns a crawl() stub that cycles through the given sequence, then hangs. */
function makeCyclingCrawl(
  sequence: Array<CrawlResult | null>,
  onComplete?: () => void,
): () => Promise<CrawlResult | null> {
  let index = 0;
  return async () => {
    if (index < sequence.length) {
      const item = sequence[index++];
      if (index === sequence.length && onComplete) onComplete();
      return item;
    }
    // Hang the loop so tests can exit via Promise.race or similar
    return new Promise<CrawlResult | null>(() => {});
  };
}

/** A sample CrawlResult for use as a non-null "work was done" sentinel. */
const SPAWNED: CrawlResult = { action: 'rig-spawned', rigId: 'rig-1', writId: 'writ-1' };
const COMPLETED: CrawlResult = { action: 'engine-completed', rigId: 'rig-1', engineId: 'draft' };

// ── crawl-one ──────────────────────────────────────────────────────────

describe('crawl-one tool', () => {
  afterEach(() => clearGuild());

  it('has name "crawl-one"', () => {
    assert.equal(crawlOneTool.name, 'crawl-one');
  });

  it('has the correct description', () => {
    assert.equal(crawlOneTool.description, "Execute one step of the Spider's crawl loop");
  });

  it('requires spider:write permission', () => {
    assert.equal(crawlOneTool.permission, 'spider:write');
  });

  it('returns a CrawlResult when work is available', async () => {
    setGuild(makeGuild(async () => SPAWNED));
    const result = await crawlOneTool.handler({});
    assert.deepEqual(result, SPAWNED);
  });

  it('returns null when there is nothing to do', async () => {
    setGuild(makeGuild(async () => null));
    const result = await crawlOneTool.handler({});
    assert.equal(result, null);
  });

  it('delegates directly to spider.crawl() with no transformation', async () => {
    const expected: CrawlResult = { action: 'engine-started', rigId: 'rig-2', engineId: 'implement' };
    setGuild(makeGuild(async () => expected));
    const result = await crawlOneTool.handler({});
    assert.deepEqual(result, expected);
  });
});

// ── crawl-continual — metadata ─────────────────────────────────────────

describe('crawl-continual tool metadata', () => {
  it('has name "crawl-continual"', () => {
    assert.equal(crawlContinualTool.name, 'crawl-continual');
  });

  it('has description without "until idle" qualifier', () => {
    assert.equal(crawlContinualTool.description, "Run the Spider's crawl loop continuously");
    assert.ok(
      !crawlContinualTool.description.includes('until idle'),
      'description must not contain "until idle"',
    );
  });

  it('requires spider:write permission', () => {
    assert.equal(crawlContinualTool.permission, 'spider:write');
  });

  it('maxIdleCycles defaults to 0 (indefinite)', () => {
    const parsed = crawlContinualTool.params.parse({});
    assert.equal(parsed.maxIdleCycles, 0);
  });

  it('instructions explain indefinite default', () => {
    const instructions = crawlContinualTool.instructions ?? '';
    assert.ok(
      instructions.includes('indefinitely'),
      'instructions must mention "indefinitely"',
    );
    assert.ok(
      instructions.includes('maxIdleCycles'),
      'instructions must mention "maxIdleCycles"',
    );
  });

  it('maxIdleCycles param describes auto-stop behavior', () => {
    // In Zod v4, .description is a top-level property on the schema
    const shape = crawlContinualTool.params.shape as Record<string, { description?: string }>;
    const desc = shape['maxIdleCycles']?.description ?? '';
    assert.ok(
      desc.includes('auto-stop') || desc.includes('runs indefinitely'),
      `maxIdleCycles description should mention auto-stop or runs indefinitely, got: "${desc}"`,
    );
  });
});

// ── crawl-continual — indefinite mode ─────────────────────────────────

describe('crawl-continual — indefinite mode (maxIdleCycles: 0)', () => {
  afterEach(() => clearGuild());

  it('does not stop after many consecutive idle cycles', async () => {
    // After 15 null returns, hang forever — if the loop stopped due to
    // idle count, the handler would resolve before the proof fires.
    let callCount = 0;
    let resolveProof!: (val: string) => void;
    const proof = new Promise<string>(r => { resolveProof = r; });

    setGuild(makeGuild(async () => {
      callCount++;
      if (callCount === 15) {
        resolveProof('still-running');
        // Hang the loop so it never resolves naturally
        return new Promise<CrawlResult | null>(() => {});
      }
      return null;
    }));

    const winner = await Promise.race([
      proof,
      crawlContinualTool.handler({ maxIdleCycles: 0, pollIntervalMs: 0 })
        .then(() => 'handler-resolved'),
    ]);

    assert.equal(winner, 'still-running', 'loop must still be running after 15 idle cycles');
    assert.equal(callCount, 15);
  });

  it('does not stop during alternating idle and work cycles', async () => {
    // idle, work, idle, work, idle ... verifies counter resets don't cause
    // premature termination even with many alternations.
    const sequence: Array<CrawlResult | null> = [
      null, SPAWNED, null, COMPLETED, null, SPAWNED, null, COMPLETED, null, SPAWNED,
    ];

    let resolveProof!: (val: string) => void;
    const proof = new Promise<string>(r => { resolveProof = r; });

    setGuild(makeGuild(makeCyclingCrawl(sequence, () => resolveProof('still-running'))));

    const winner = await Promise.race([
      proof,
      crawlContinualTool.handler({ maxIdleCycles: 0, pollIntervalMs: 0 })
        .then(() => 'handler-resolved'),
    ]);

    assert.equal(winner, 'still-running', 'indefinite loop must not resolve on alternating idle/work');
  });
});

// ── crawl-continual — auto-stop mode ──────────────────────────────────

describe('crawl-continual — auto-stop mode (positive maxIdleCycles)', () => {
  afterEach(() => clearGuild());

  it('stops after maxIdleCycles=2 consecutive idles', async () => {
    setGuild(makeGuild(async () => null));

    const result = await crawlContinualTool.handler({ maxIdleCycles: 2, pollIntervalMs: 0 }) as {
      actions: unknown[];
      totalActions: number;
    };

    assert.deepEqual(result, { actions: [], totalActions: 0 });
  });

  it('stops after maxIdleCycles=1 (single idle)', async () => {
    setGuild(makeGuild(async () => null));

    const result = await crawlContinualTool.handler({ maxIdleCycles: 1, pollIntervalMs: 0 }) as {
      actions: unknown[];
      totalActions: number;
    };

    assert.deepEqual(result, { actions: [], totalActions: 0 });
  });

  it('collects action results in the returned summary', async () => {
    // Two work results followed by enough idles to stop
    let callCount = 0;
    setGuild(makeGuild(async () => {
      callCount++;
      if (callCount === 1) return SPAWNED;
      if (callCount === 2) return COMPLETED;
      return null; // Will idle to stop
    }));

    const result = await crawlContinualTool.handler({ maxIdleCycles: 2, pollIntervalMs: 0 }) as {
      actions: unknown[];
      totalActions: number;
    };

    assert.equal(result.totalActions, 2);
    assert.deepEqual(result.actions, [SPAWNED, COMPLETED]);
  });

  it('resets idle counter on work and stops after trailing idles (idle, idle, work, idle, idle, idle)', async () => {
    // Sequence: null, null, SPAWNED, null, null, null
    // With maxIdleCycles=3:
    //   - cycle 1: null → idleCount=1
    //   - cycle 2: null → idleCount=2
    //   - cycle 3: SPAWNED → idleCount=0 (reset)
    //   - cycle 4: null → idleCount=1
    //   - cycle 5: null → idleCount=2
    //   - cycle 6: null → idleCount=3 → exit (idleCount >= maxIdle)
    const sequence: Array<CrawlResult | null> = [null, null, SPAWNED, null, null, null];
    let callCount = 0;

    setGuild(makeGuild(async () => {
      const item = sequence[callCount++] ?? null;
      return item;
    }));

    const result = await crawlContinualTool.handler({ maxIdleCycles: 3, pollIntervalMs: 0 }) as {
      actions: unknown[];
      totalActions: number;
    };

    assert.equal(callCount, 6, 'must process all 6 cycles before stopping');
    assert.equal(result.totalActions, 1);
    assert.deepEqual(result.actions, [SPAWNED]);
  });

  it('does not terminate early when work resets idle count below threshold', async () => {
    // Sequence: null, work, null, work, null, null → maxIdleCycles=2 → stops after trailing 2 idles
    const sequence: Array<CrawlResult | null> = [null, SPAWNED, null, COMPLETED, null, null];
    let callCount = 0;

    setGuild(makeGuild(async () => {
      return sequence[callCount++] ?? null;
    }));

    const result = await crawlContinualTool.handler({ maxIdleCycles: 2, pollIntervalMs: 0 }) as {
      actions: unknown[];
      totalActions: number;
    };

    assert.equal(callCount, 6);
    assert.equal(result.totalActions, 2);
    assert.deepEqual(result.actions, [SPAWNED, COMPLETED]);
  });
});

// ── crawl-continual — error handling ──────────────────────────────────

describe('crawl-continual — error handling', () => {
  let originalConsoleError: typeof console.error;
  let errorLogs: string[];

  beforeEach(() => {
    errorLogs = [];
    originalConsoleError = console.error;
    // Capture console.error calls without printing them
    console.error = (...args: unknown[]) => {
      errorLogs.push(args.map(a => (typeof a === 'string' ? a : String(a))).join(' '));
    };
  });

  afterEach(() => {
    console.error = originalConsoleError;
    clearGuild();
  });

  it('logs [crawl-continual] tag when crawl() throws an Error', async () => {
    setGuild(makeGuild(async () => { throw new Error('boom'); }));

    await crawlContinualTool.handler({ maxIdleCycles: 1, pollIntervalMs: 0 });

    assert.ok(
      errorLogs.some(l => l.includes('[crawl-continual]')),
      `expected [crawl-continual] in console.error, got: ${JSON.stringify(errorLogs)}`,
    );
  });

  it('includes the error message in the log output', async () => {
    setGuild(makeGuild(async () => { throw new Error('specific error message'); }));

    await crawlContinualTool.handler({ maxIdleCycles: 1, pollIntervalMs: 0 });

    assert.ok(
      errorLogs.some(l => l.includes('specific error message')),
      `expected error message in log, got: ${JSON.stringify(errorLogs)}`,
    );
  });

  it('handles non-Error throws (strings, objects)', async () => {
    setGuild(makeGuild(async () => { throw 'string error'; }));  // eslint-disable-line @typescript-eslint/no-throw-literal

    await crawlContinualTool.handler({ maxIdleCycles: 1, pollIntervalMs: 0 });

    assert.ok(
      errorLogs.some(l => l.includes('string error')),
      `expected stringified error in log, got: ${JSON.stringify(errorLogs)}`,
    );
  });

  it('increments idle count on error and stops after maxIdleCycles errors', async () => {
    let callCount = 0;
    setGuild(makeGuild(async () => {
      callCount++;
      throw new Error(`error #${callCount}`);
    }));

    const result = await crawlContinualTool.handler({ maxIdleCycles: 2, pollIntervalMs: 0 }) as {
      actions: unknown[];
      totalActions: number;
    };

    assert.equal(callCount, 2, 'must call crawl() exactly maxIdleCycles times before stopping');
    assert.deepEqual(result, { actions: [], totalActions: 0 });
  });

  it('resets idle count on success after errors', async () => {
    // error, error, work, error, error → with maxIdleCycles=2
    // after 2 errors idleCount=2 = maxIdle, but that triggers the EXIT condition...
    // Wait, with: error (idleCount=1), error (idleCount=2) → exits. So this won't reach work.
    // Instead test: error, work, error, error → maxIdleCycles=2
    // error: idleCount=1, work: idleCount=0, error: idleCount=1, error: idleCount=2 → exit
    let callCount = 0;
    const sequence: Array<'error' | CrawlResult | null> = ['error', SPAWNED, 'error', 'error'];
    setGuild(makeGuild(async () => {
      const item = sequence[callCount++];
      if (item === 'error') throw new Error(`error at #${callCount}`);
      return item as CrawlResult | null;
    }));

    const result = await crawlContinualTool.handler({ maxIdleCycles: 2, pollIntervalMs: 0 }) as {
      actions: unknown[];
      totalActions: number;
    };

    assert.equal(callCount, 4);
    assert.equal(result.totalActions, 1);
    assert.deepEqual(result.actions, [SPAWNED]);
  });
});

// ── crawl-continual — poll interval ───────────────────────────────────

describe('crawl-continual — poll interval configuration', () => {
  afterEach(() => clearGuild());

  it('uses pollIntervalMs param over guild config', async () => {
    // We verify this indirectly: if the tool runs without error and the
    // param is accepted, the interval is being used. We set pollIntervalMs: 0
    // to avoid real delays and confirm the run completes quickly.
    setGuild(makeGuild(async () => null, { pollIntervalMs: 999999 }));

    const start = Date.now();
    await crawlContinualTool.handler({ maxIdleCycles: 1, pollIntervalMs: 0 });
    const elapsed = Date.now() - start;

    // With pollIntervalMs: 0, should complete near-instantly (well under 500ms)
    assert.ok(elapsed < 500, `expected fast completion with pollIntervalMs:0, took ${elapsed}ms`);
  });

  it('uses guild config pollIntervalMs when param is not provided', async () => {
    // Not providing pollIntervalMs param — guild config has pollIntervalMs:0
    // so it still completes quickly.
    setGuild(makeGuild(async () => null, { pollIntervalMs: 0 }));

    const start = Date.now();
    await crawlContinualTool.handler({ maxIdleCycles: 1 });
    const elapsed = Date.now() - start;

    assert.ok(elapsed < 500, `expected fast completion with config pollIntervalMs:0, took ${elapsed}ms`);
  });
});

# Building Engines

This guide explains how to build clockwork engines — event-driven handlers that respond to guild events via standing orders. For building interactive tools that animas wield, see [Building Tools](building-tools.md).

## What engines are

Engines are automated processes with no AI involvement. They run deterministic logic in response to events: rolling up completion status, dispatching work, transforming data, enforcing policies. They don't have instruction documents because no anima wields them — they're guild infrastructure.

Engines are wired to events through **standing orders** in `guild.json`. When an event fires, the Clockworks runner finds matching standing orders and calls the engine's handler with the event.

## Quick start

An engine is a package with these files:

```
my-engine/
  package.json              ← npm package metadata
  nexus-engine.json         ← Nexus descriptor
  src/
    handler.ts              ← the engine handler (default export)
```

### The handler

Use the `engine()` factory from `@shardworks/nexus-core`:

```typescript
import { engine } from '@shardworks/nexus-core';

export default engine({
  name: 'my-engine',
  handler: async (event, { home, params }) => {
    // event  — the GuildEvent that triggered this engine (or null for direct invocation)
    // home   — absolute path to the guild root
    // params — extra keys from the standing order that invoked this engine

    if (!event) return; // nothing to do without an event

    console.log(`Handling ${event.name}`, event.payload);

    // Do your work here...
  }
});
```

### Key rules

1. **Default export.** The engine must be the default export. The Clockworks runner does `import(modulePath)` and reads `.default`.
2. **Async handler.** Engine handlers must return `Promise<void>`. The runner `await`s the handler.
3. **Event may be null.** When invoked directly (not via a standing order), `event` is `null`. Guard accordingly.
4. **Throw for errors.** If the handler throws, the Clockworks runner catches the error, records a failed dispatch, and signals `standing-order.failed`.
5. **Use `home` for everything.** The guild root is your entry point to all guild state — database, config, file system.
6. **Params are untyped.** `params` is `Record<string, unknown>` — cast to expected types in your handler. Provide sensible defaults.

### `nexus-engine.json`

```json
{
  "entry": "src/handler.ts",
  "version": "0.1.0",
  "description": "What this engine does"
}
```

Fields:
- `entry` — (required) path to the handler module
- `version` — informational, recorded in guild.json `upstream`
- `description` — human-readable

### `package.json`

```json
{
  "name": "@shardworks/engine-my-engine",
  "version": "0.1.0",
  "type": "module",
  "exports": {
    ".": "./src/handler.ts"
  },
  "dependencies": {
    "@shardworks/nexus-core": "workspace:*"
  }
}
```

Engines don't need `zod` (no parameter validation) or instruction files (no anima interaction).

## Standing order wiring

Engines are connected to events through standing orders in `guild.json`:

```json
{
  "clockworks": {
    "standingOrders": [
      { "on": "session.ended", "run": "my-engine" },
      { "on": "task.completed", "run": "my-engine" }
    ]
  }
}
```

An engine can respond to multiple events. Multiple engines can respond to the same event — they execute in declaration order.

### Passing params to engines

Any key on a standing order that isn't `on` or `run` is passed to the engine as a param:

```json
{ "on": "deploy.requested", "run": "deploy", "environment": "staging", "dryRun": true }
```

The engine receives these in `params`:

```typescript
handler: async (event, { home, params }) => {
  const environment = (params.environment as string) ?? 'production';
  const dryRun = (params.dryRun as boolean) ?? false;
}
```

This lets the same engine serve multiple standing orders with different configurations. Params default to `{}` when no extra keys are present.

The engine must also be registered in guild.json's `engines` registry:

```json
{
  "engines": {
    "my-engine": {
      "upstream": "@shardworks/engine-my-engine@0.1.0",
      "installedAt": "2026-03-25T00:00:00.000Z",
      "package": "@shardworks/engine-my-engine"
    }
  }
}
```

This happens automatically when installed via `nsg tool install`.

## Reading guild state from an engine

Engines have full access to `@shardworks/nexus-core`. Common patterns:

### Reading event payloads

```typescript
handler: async (event, { home }) => {
  if (!event) return;

  // Event payloads are typed as `unknown` — cast based on the event name
  const payload = event.payload as { writId: string } | null;
  if (!payload?.writId) return;

  // Now use the writId...
}
```

### Querying the database

```typescript
import { showWrit, listWrits, readGuildConfig } from '@shardworks/nexus-core';

handler: async (event, { home }) => {
  const writ = showWrit(home, writId);
  if (!writ) return;

  const children = listWrits(home, { parentId: writ.id });
  const config = readGuildConfig(home);
  // ...
}
```

### Writing to the database

```typescript
import { completeWrit, signalEvent } from '@shardworks/nexus-core';

handler: async (event, { home }) => {
  // Complete a writ — this automatically signals {type}.completed
  completeWrit(home, writId);
}
```

## Signaling follow-on events

Engines can signal events to trigger further automation (event chaining):

```typescript
import { signalEvent } from '@shardworks/nexus-core';

handler: async (event, { home }) => {
  // Do some work...

  // Signal a custom event for downstream processing
  signalEvent(home, 'deploy.ready', { version: '1.2.3' }, 'my-engine');
}
```

**Important:** Writ lifecycle events (like `task.completed`) are signaled automatically by `completeWrit()` and `failWrit()`. Don't double-signal — just call the appropriate function and the event fires.

For custom events, you must declare them in `guild.json` first if animas need to signal them. Engines can signal framework events directly (they call `signalEvent()`, which doesn't go through `validateCustomEvent()`).

## Error handling

### The `standing-order.failed` safety net

When an engine handler throws, the Clockworks runner:

1. Catches the error
2. Records a failed dispatch in `event_dispatches` (with the error message)
3. Signals `standing-order.failed` with the original event, the standing order, and the error

You can wire a standing order to `standing-order.failed` for alerting:

```json
{ "on": "standing-order.failed", "brief": "steward" }
```

**Loop guard:** If processing a `standing-order.failed` event itself fails, the runner stops — it won't cascade infinitely.

### Best practices

- **Fail fast.** Throw with a clear error message. Don't swallow errors silently.
- **Idempotency.** Design handlers to be safe to retry. The same event might be processed again if the runner is restarted.
- **Guard against missing data.** Event payloads may be incomplete. Check for null/undefined before accessing fields.

## Engine collections

A single package can export multiple engines:

```typescript
import { engine } from '@shardworks/nexus-core';

export default [
  engine({
    name: 'writ-notify',
    handler: async (event, { home }) => { /* ... */ }
  }),
  engine({
    name: 'writ-audit',
    handler: async (event, { home }) => { /* ... */ }
  }),
];
```

Each engine in the array is resolved by name. Register each one separately in guild.json with the same `package` but different names.

## Installing engines

Same as tools — use `nsg tool install`:

```bash
nsg tool install @shardworks/engine-my-engine
```

The installer detects `nexus-engine.json` and registers in the `engines` section of guild.json (not `tools`). All five install types work: registry, git-url, workshop, tarball, link.

## Testing engines

Engine handlers can be called directly in tests:

```typescript
import { describe, it, beforeEach } from 'node:test';
import assert from 'node:assert/strict';
import { initGuild, createWrit, completeWrit, showWrit } from '@shardworks/nexus-core';
import myEngine from './handler.ts';

describe('my-engine', () => {
  let home: string;

  beforeEach(() => {
    home = '/tmp/test-guild-' + Date.now();
    initGuild(home, 'test-guild', 'test-model');
  });

  it('processes a completed writ event', async () => {
    // Set up test data
    const writ = createWrit(home, { type: 'task', title: 'Test task' });
    completeWrit(home, writ.id);

    // Simulate the event
    await myEngine.handler(
      {
        id: 'evt-test',
        name: 'task.completed',
        payload: { writId: writ.id },
        emitter: 'framework',
        firedAt: new Date().toISOString(),
      },
      { home, params: {} }
    );

    // Verify the result
    const updated = showWrit(home, writ.id);
    assert.equal(updated?.status, 'completed');
  });
});
```

For integration testing with the full Clockworks, use `clockTick()`:

```typescript
import { clockTick, signalEvent } from '@shardworks/nexus-core';

// Signal an event
signalEvent(home, 'task.completed', { writId: 'wrt-test' }, 'test');

// Process it through the Clockworks (requires standing orders in guild.json)
const result = await clockTick(home);
assert.equal(result?.eventName, 'task.completed');
```

## Reference implementation: notification engine

A concrete engine that sends a notification when a mandate completes — a simple pattern for post-completion automation.

```typescript
import { engine, showWrit, readCommission } from '@shardworks/nexus-core';

export default engine({
  name: 'mandate-notify',
  handler: async (event, { home }) => {
    if (!event) return;

    // This engine responds to mandate.completed events
    const payload = event.payload as { writId?: string; commissionId?: string } | null;
    if (!payload?.writId) return;

    const writ = showWrit(home, payload.writId);
    if (!writ) return;

    // Look up the commission for context
    const commission = payload.commissionId
      ? readCommission(home, payload.commissionId)
      : null;

    console.log(`Mandate "${writ.title}" completed for commission ${commission?.id ?? 'unknown'}`);
    // In a real engine: send a Slack message, write a summary, etc.
  }
});
```

Wire it in guild.json:

```json
{
  "clockworks": {
    "standingOrders": [
      { "on": "mandate.completed", "run": "mandate-notify" }
    ]
  }
}
```

**Note:** Completion rollup for writs is handled automatically by the framework. When all children of a writ complete, the parent transitions from `pending` → `ready` (or auto-completes). You don't need a custom engine for rollup — the framework does it internally when `completeWrit()` or `failWrit()` is called.

## Further reading

- [Core API Reference](../reference/core-api.md) — full function signatures for all imports
- [Event Catalog](../reference/event-catalog.md) — every framework event, payload shapes, standing order types
- [Schema Reference](../reference/schema.md) — database tables, status lifecycles, entity relationships
- [The Clockworks](../architecture/clockworks.md) — architectural overview of the event processing system

